import Nav from '@/components/Nav'; import { requireUser } from '@/lib/auth'; import { prisma } from '@/lib/db'; import Link from 'next/link';
export default async function Dashboard(){ const user=await requireUser(); const enrollments=await prisma.enrollment.findMany({where:{userId:user.id},include:{course:{include:{sections:{include:{lessons:true}}}}}}); return <><Nav/><main className="mx-auto max-w-7xl px-5 py-10"><h1 className="text-4xl font-black">Welcome, {user.name}</h1><p className="text-slate-600">Role: {user.role}</p><div className="mt-8 grid gap-6 md:grid-cols-2">{enrollments.map(e=><Link href={`/learn/${e.course.id}`} key={e.id} className="card p-6"><h2 className="text-2xl font-black">{e.course.title}</h2><p className="mt-2 text-slate-600">Continue learning with resources, discussions and AI support.</p><span className="btn mt-5">Continue</span></Link>)}</div></main></> }
